(function () {
    var rawKK = getValue('no_kk');

    // skip kalau kosong (anggap optional, ubah kalau mau wajib)
    if (!rawKK) return false;

    // reject spasi
    if (rawKK !== rawKK.trim()) return true;

    // hanya boleh angka
    if (!/^[0-9]+$/.test(rawKK)) return true;

    // allow sentinel
    if (rawKK === "7777" || rawKK === "8888" || rawKK === "9999") {
        return false;
    }

    // selain itu harus tepat 16 digit
    return !/^[0-9]{16}$/.test(rawKK);
})();

