    if (!arr || !Array.isArray(arr) || jumlahAk == null) return false;

    var countValidList = 0;
    var countDtsenMatch = 0;
    var allFilled = true;

    for (var i = 0; i < arr.length; i++) {
        var val = arr[i]?.value;
        if (!val || val == '0') continue;

        countValidList++;

        var dtsen = getValue('keberadaan_dtsen#' + val)?.[0].value;

        // cek apakah semua sudah terisi
        if (!dtsen) {
            allFilled = false;
