        // hitung yang memenuhi 1 atau 5
        if (dtsen == 1 || dtsen == 5) {
            countDtsenMatch++;
        }
    }

    // ? kondisi trigger validasi
    if (!allFilled || countValidList < jumlahAk) {
        return false; // skip validasi
