const nama_usaha_bang = getValue('nama_usaha_bang') ?? '';

const lp = p.length;
const tp = t.length;

/** PARSE UMKM **/
const umkmData = getValue('pilih_umkm')?.[0] || {};
const str = umkmData?.description || '';
const nama = umkmData?.label || '';

let idsbr = '';

if (str.includes('[') && str.includes(']')) {
  const firstEnd = str.indexOf(']');
  const secondStart = str.indexOf('[', firstEnd) + 1;
  const secondEnd = str.indexOf(']', secondStart);
  idsbr = parseInt(str.substring(secondStart, secondEnd)) || '';
}

/** RESULT **/
let hasil = [];
let nus = 1;

/** HELPER: prevent duplicate label **/
const exists = (label) => hasil.some(h => h.label === label);

/** ===================== */
/** 1. PRELIST */
/** ===================== */
p.forEach(item => {
  if (!exists(item?.label)) {
    let nama_usaha = getValue('nama_usaha_edit#' + (Number(item?.value))) ??
    item?.label

    hasil.push({
      value: item?.value || '',
      label: nama_usaha,
      is_prelist: "1",
      nousaha: nus,
      id_pmss: item?.id_pmss || '',
      idsbr: item?.idsbr || ''
    });
    nus++
  }
});


/** ===================== */
/** 2. ART (ANGGOTA RUMAH TANGGA) */
/** ===================== */
const art_gabung = getValue('gabung_dtsen') || [];

art_gabung.forEach((art,index) => {
  const ada = getVal('art_ada_usaha#' + art.value);
  const nama_pengusaha_prelist = getValue('daftar_nik_pengusaha') ?? [];
  let nama_art = getValue('nama_dtsen#' + art.value);
  let nik = getValue('nik_dtsen#' + art.value)?.toString();
  let nik_prelist = getValue('nik_dtsen_prelist#' + art.value)?.toString();
  let nama_usaha = getValue('nama_usaha_edit#' + (1000 + Number(art.value))) ?? "Usaha " + nama_art

  const nik_matching_prelist = nama_pengusaha_prelist.includes(nik) || nama_pengusaha_prelist.includes(nik_prelist)

  if (ada == '1' && !nik_matching_prelist) {
    hasil.push({
      value: 1000 + Number(art.value),
      label: nama_usaha,
      index_art: art.value,
      nama_art: nama_art,
      is_prelist: "0",
      nousaha: nus,
      id_pmss: '',
      idsbr: ''
    });
    nus++
  }
});

/** ===================== */
/** 3. UMKM & BANGUNAN */
/** ===================== */
if (getValue('ec_ada_usaha') && !prelist) {

  const kodeBang = getVal('kode_bang');

  // Bangunan
  if ((kodeBang == '1' || kodeBang == '7')) {
    const labelBang = nama_usaha_bang || 'Usaha Bangunan';

    if (!exists(labelBang)) {
      hasil.push({
        value: 2001,
        label: labelBang,
        is_prelist: "0",
        nousaha: nus,
        id_pmss: idsbr,
        idsbr: idsbr
      });
      nus++
    }
  }

  // UMKM pilihan
  if (
    nama &&
    nama !== 'Tidak Ditemukan' &&
    getVal('is_new') == '2' &&
    !exists(nama)
  ) {
    hasil.push({
      value: 1,
      label: nama,
      is_prelist: "1",
      nousaha: nus,
      id_pmss: idsbr,
      idsbr: idsbr
    });
    nus++
  }
}

/** ===================== */
/** 5. TAMBAHAN */
/** ===================== */
if (
  tp > 1
) {
  for (let i = 1; i < tp; i++) {
    const labelTambahan = t[i]?.label || '';

    if (labelTambahan && !exists(labelTambahan)) {
      hasil.push({
        value: 3000 + (t[i]?.value || 0),
        label: labelTambahan,
        is_prelist: "0",
        nousaha: nus,
        id_pmss: "",
        idsbr: ""
      });
      nus++
    }
  }
}

/** ===================== */
/** FINAL SORT (OPTIONAL) */
/** ===================== */
hasil.sort((a, b) => {
  // Prelist first
  if (a.is_prelist !== b.is_prelist) {
    return b.is_prelist.localeCompare(a.is_prelist);
  }
  // then by nousaha
  return a.nousaha - b.nousaha;
});

