      ">
        ${title}
      </div>

      ${
        message
          ? `
          <div style="
            font-size:12px;
            color:#4b5563;
          ">
            ${message}
          </div>
          `
          : ""
      }
    </div>
  `;

  Promise.resolve(
    fetchExternalData("pemadanan_nik", { nik })
  )
    .then((response) => {

     response = typeof response == 'string' ? JSON.parse(response) : response


      setValue(
        "result_callnik#" + rowIndex,
        response
      );

      const data = response?.data || {};

      const error =
        response?.data?.code ||
        response?.error ||
        "";

      const message =
        response?.data?.message ||
        response?.message ||
        "";

      const statusKode = String(
        data?.statusKode || ""
      );

      const namaApi = String(
        data?.nama || ""
      ).trim();

      const namaApiNorm =
        namaApi.toLowerCase();

      let hasil;
      let html;

      // ==========================================
      // ERROR API
      // ==========================================

      if (error) {

        hasil = "[4] " + error;

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "GAGAL MENGAMBIL DATA",
          message: message || error
        });

      }

      // ==========================================
      // NIK & NAMA SESUAI
      // ==========================================

      else if (
        statusKode &&
        statusKode !== "3" &&
        namaApiNorm === namaInput
      ) {

        hasil =
          "[1] NIK ditemukan dan Nama sesuai";

        html = createAlert({
          bg: "#EFF6FF",
          border: "#93C5FD",
          color: "#1D4ED8",
          title: "NIK & NAMA SESUAI",
          message: `
            <div>${nik}</div>
            <div>${maskNama(namaApi)}</div>
          `
        });

      }

      // ==========================================
      // NIK DITEMUKAN, NAMA TIDAK SESUAI
      // ==========================================

      else if (
        statusKode &&
        statusKode !== "3"
      ) {

        hasil =
          "[2] NIK ditemukan dan Nama tidak sesuai";

        html = createAlert({
          bg: "#FFF7ED",
          border: "#FDBA74",
          color: "#C2410C",
          title: "NAMA TIDAK SESUAI",
          message: `
            <div>${nik}</div>
            <div>Data Dukcapil: ${maskNama(namaApi)}</div>
            <div>Data Input: ${namaInputRaw}</div>
          `
        });

      }

      // ==========================================
      // NIK TIDAK DITEMUKAN
      // ==========================================

      else if (statusKode === "3") {

        hasil =
          "[3] NIK tidak ditemukan";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "NIK TIDAK DITEMUKAN",
          message: nik
        });

      }

      // ==========================================
      // FALLBACK
      // ==========================================

      else {

        hasil =
          "[4] Gagal mengambil data";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "GAGAL MENGAMBIL DATA"
        });

      }

      setValue(
        "hasilPemadananNIK#" + rowIndex,
        hasil
      );

      setValue(
        "htmlHasilPemadananNIK#" + rowIndex,
        html
      );

      setValue(
        "htmlHasilPemadananNIK2#" + rowIndex,
        statusKode
      );

    })
    .catch((error) => {

      console.log(error);

      setValue(
        "hasilPemadananNIK#" + rowIndex,
        "[4] Gagal mengambil data"
      );

      setValue(
        "htmlHasilPemadananNIK#" + rowIndex,
