(function () {
    let d = new Date();

    let vthnLahir = getValue('thn_lahir@$ROW$');
    let vblnLahir = getValue('bln_lahir@$ROW$');
    let vtglLahir = getValue('tgl_lahir@$ROW$');

    // ? kalau tahun belum ada ? jangan hitung
    if (!vthnLahir) return "";

    let thnLahir = Number(vthnLahir);
    let blnLahir = vblnLahir ? Number(vblnLahir?.[0]?.value) : 0;
    let tglLahir = vtglLahir ? Number(vtglLahir) : 0;

    // handle sentinel 98 ? fallback ke 1
    blnLahir = blnLahir == 98 ? 1 : blnLahir;
    tglLahir = tglLahir == 98 ? 1 : tglLahir;

    function hitungUmur(tgl, bln, thn) {
        const hariIni = new Date();
        const tanggalLahir = new Date(thn, bln - 1, tgl);

        let bedaMs = hariIni - tanggalLahir;
        const msPerYear = 1000 * 60 * 60 * 24 * 365.25;

        return Math.floor(bedaMs / msPerYear);
    }

    // kalau bulan/tanggal belum ada ? tetap bisa hitung (pakai fallback 1)
    if (!blnLahir) blnLahir = 1;
    if (!tglLahir) tglLahir = 1;

    let age = hitungUmur(tglLahir, blnLahir, thnLahir);

    setTimeout(() => setValue('umur_ak@$ROW$', age));
})();

