function transformToObjects(input) {
  const keys = Object.keys(input);
  const length = input[keys[0]].length;

  return Array.from({ length }, (_, i) => {
    const obj = {};
    keys.forEach(key => {
      obj[key] = input[key][i] ?? "";
    });
    return obj;
  });
}

