(function () {
    let kategori = getValue('kategori@$ROW$');
    let kbli = getValue('kbli_akhir@$ROW$') ?? '';

    let kbli2 = kbli.substring(0, 2);

    // Produksi
    if (/^[B-F]$/.test(kategori)) {
        return 'produksi';
    }

    // Penjualan
    if (kategori == 'G' && (kbli2 == '46' || kbli2 == '47')) {
        return 'penjualan';
    }

    // Pendapatan
    if (/^(H|I|J|K|L|M|N|Q|R|S|T|U)$/.test(kategori)) {
        return 'pendapatan';
    }

    return 'produksi/pendapatan/penjualan';
})();

