components.enableCondition:
(function () {
    let kbli = getValue('kbli_akhir@$ROW$') ?? '';
    let kategori = getValue('kategori@$ROW$');
    let bulan = getValue('ec_usaha_bulan@$ROW$');

    let isPerdagangan =
        kategori == 'G'
        && !/^(46100|47901|47909)$/.test(kbli);

    let isValas =
        kategori == 'L'
        && /^(66125|64994)$/.test(kbli);

    let isPulsa =
        kategori == 'K'
        && kbli == '61909';

    return bulan && (isPerdagangan || isValas || isPulsa);
})();

