try {

  const id_pelanggan = String(
    getValue("id_pelanggan@$ROW$") || ""
  );

  const maskNama = (nama = "") =>
    nama
      .trim()
      .split(/\s+/)
      .map(kata => {
        if (kata.length <= 2) return kata;

        return (
          kata[0] +
          "*".repeat(kata.length - 2) +
          kata[kata.length - 1]
        );
      })
      .join(" ");

  const createAlert = ({
    bg,
    border,
    color,
    title,
    message = ""
  }) => `
    <div style="
      background:${bg};
      border:1px solid ${border};
      border-radius:6px;
      padding:10px 12px;
      text-align:center;
      line-height:1.4;
    ">
      <div style="
        font-size:13px;
        font-weight:700;
        color:${color};
        margin-bottom:${message ? "4px" : "0"};
      ">
        ${title}
      </div>

      ${
        message
          ? `
          <div style="
            font-size:12px;
            color:#4b5563;
          ">
            ${message}
          </div>
          `
          : ""
      }
    </div>
  `;

  Promise.resolve(
    fetchExternalData(
      "check-idpln",
      {
        id_pelanggan_pln:
          id_pelanggan
      }
    )
  )
    .then((result) => {

     result = typeof result == 'string' ? JSON.parse(result) : result


      setValue(
        "result_cekidpel@$ROW$",
        result
      );

      const res =
        typeof result === "string"
          ? JSON.parse(result)
          : result;

      const data = res?.data || {};

      const fasihExists =
        data?.fasih_exists;

      const exists =
        data?.exists;

      const nama =
        data?.nama || "";

      const alamat =
        data?.alamat || "";

      const idPelangganApi =
        data?.id_pelanggan ||
        id_pelanggan;

      const message =
        res?.message || "";

      const error =
        res?.error || "";

      let hasil;
      let html;

      // ==========================================
      // TIDAK ADA INTERNET
      // ==========================================

      if (
        error ===
        "No internet connection"
      ) {

        hasil =
          "[4] Gagal mengambil data: Tidak ada koneksi internet";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "TIDAK ADA KONEKSI",
          message:
            "Periksa koneksi internet lalu coba kembali."
        });

      }

      // ==========================================
      // ID PELANGGAN TERCATAT DI FASIH
      // ==========================================

      else if (
        exists === true &&
        fasihExists === true
      ) {

        hasil =
          "[1] ID Pelanggan ditemukan dan tercatat pada Sistem FASIH";

        html = createAlert({
          bg: "#EFF6FF",
          border: "#93C5FD",
          color: "#1D4ED8",
          title: "ID PELANGGAN DITEMUKAN DAN TERCATAT DI FASIH",
          message: `
            <div>${idPelangganApi}</div>
            <div>${maskNama(nama)}</div>
          `
        });

      }

      // ==========================================
      // ID PELANGGAN DITEMUKAN TAPI BELUM FASIH
      // ==========================================

      else if (
        exists === true &&
        fasihExists === false
      ) {

        hasil =
          "[2] ID Pelanggan ditemukan tetapi belum tercatat pada Sistem FASIH";

        html = createAlert({
          bg: "#FFF7ED",
          border: "#FDBA74",
          color: "#C2410C",
          title: "ID PELANGGAN DITEMUKAN TETAPI BELUM TERCATAT DI FASIH",
          message: `
            <div>${idPelangganApi}</div>
            <div>${maskNama(nama)}</div>
          `
        });

      }

      // ==========================================
      // ID PELANGGAN TIDAK DITEMUKAN
      // ==========================================

      else if (
        exists === false
      ) {

        hasil =
          "[3] ID Pelanggan tidak ditemukan";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "ID PELANGGAN TIDAK DITEMUKAN",
          message:
            id_pelanggan
        });

      }

      // ==========================================
      // ERROR API
      // ==========================================

      else if (
        error ||
        message
      ) {

        hasil =
          "[4] Gagal mengambil data";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "GAGAL MENGAMBIL DATA",
          message:
            message || error
        });

      }

      // ==========================================
      // FALLBACK
      // ==========================================

      else {

        hasil =
          "[4] Gagal mengambil data";

        html = createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title: "GAGAL MENGAMBIL DATA"
        });

      }

      setValue(
        "hasilCekIdPel@$ROW$",
        hasil
      );

      setValue(
        "htmlHasilCekIdPel@$ROW$",
        html
      );

    })
    .catch((error) => {

      console.log(error);

      setValue(
        "hasilCekIdPel@$ROW$",
        "[4] Gagal mengambil data"
      );

      setValue(
        "htmlHasilCekIdPel@$ROW$",
        createAlert({
          bg: "#FEF2F2",
          border: "#FCA5A5",
          color: "#B91C1C",
          title:
            "TERJADI KESALAHAN SISTEM",
          message:
            "Silakan coba kembali beberapa saat lagi."
        })
      );

    });

} catch (error) {

  console.log(error);

  setValue(
    "hasilCekIdPel@$ROW$",
    "[4] Gagal mengambil data"
  );


}

