(function () {
    function transformToObjects(input) {
        const keys = Object.keys(input);
        const length = input[keys[0]]?.length || 0;

        return Array.from({ length }, (_, i) => {
            const obj = {};
            keys.forEach(key => {
                obj[key] = input[key][i] ?? "";
            });
            return obj;
        });
    }
    
    const idsbrList = String(getValue("idsbr_all") || "")
      .split(/\s*,\s*/)
      .map(item => {
        const parts = String(item).split(/\s*\/\s*/);
        return parts.length > 1 ? parts[1] : parts[0];
      })
      .filter(v => v && v !== "-");

    const arr = getPrincipalCollection(["data1", "data2", "data10"]);

    const result = transformToObjects(arr).find(row => {
        const data10List = String(row.data10 || "")
            .split(/\s*,\s*/)
            .filter(Boolean);

        return idsbrList.some(id => data10List.includes(id));
    });

    if (result) {
        return {
            label: `${result.data1} - ${result.data2}`,
            value: idsbrList.join(", ")
        };
    }

    return null;
})()

