const initial_result = getValue('daftar_anomali') ?? {}

const result = {...initial_result}

const usaha_gabung = getValue('usaha_gabung') ?? [];

const cek_anomali = (rule) => {
    const daftar_anomali = []
    
    for (const usaha of usaha_gabung) {
        const index = usaha.value;
        const val = (dataKey) => getValue(dataKey + '#' + index)
        const anomali = rule.checkFn(val)
        if (anomali) daftar_anomali.push(anomali)
    }
    
    if (daftar_anomali.length) {
        result[rule.no] = {
            no: rule.no,
            message: rule.deskripsi,
            column: rule.column,
            daftar_anomali: daftar_anomali
        }
    } else {
        result[rule.no] = undefined
    }
}


const now = new Date()

if (!getValue('tanggal_anomali')) setValue('tanggal_anomali', now.toISOString())

const active_anomalies = Object.values(result).filter(n => !!n);

const anomali_solved = active_anomalies.every(anomali => {
    const catatan = getValue(`anomali_${anomali.no}_penjelasan`);

    return catatan && String(catatan).trim() !== ''; 
});

// Jika semua anomali sudah solved (atau tidak ada anomali) dan role adalah pencacah
if (anomali_solved && getConfig().user?.role.toLowerCase() === 'pencacah') {
    setValue('tanggal_selesai_anomali', now.toISOString());
} else if (!anomali_solved) {
    // atau catatan dihapus oleh user
    setValue('tanggal_selesai_anomali', null);
}

for (const rule of RULE_ANOMALI) { cek_anomali(rule) }

if (JSON.stringify(result) !== JSON.stringify(initial_result)) {
    setTimeout(() => setValue('daftar_anomali', {...result}))
}

