        return "";
    }

    const columns = Object.keys(anomali.column || {});
    const rows = anomali.daftar_anomali || [];

    const headerHtml = `
        <th style="
            padding:8px 12px;
            border:1px solid #d9e2ec;
            background:#f5f7fa;
            text-align:center;
            font-weight:600;
            width:60px;
