                    padding:8px 12px;
                    border:1px solid #d9e2ec;
                    background:#f5f7fa;
                    text-align:left;
                    font-weight:600;
                ">
                    ${anomali.column[key]}
                </th>
            `)
            .join("")}
    `;

    const bodyHtml = rows
        .map((row, rowIndex) => {
            const cells = columns
                .map(key => {
                    let value = row[key];
                    return `
                        <td style="
